To remove the `click` event listener from the map after the user has added a new station by clicking on the map, you can use the map's `off` method to remove the event listener. Here's how you can modify the code to achieve this:

```javascript
document.getElementById("newStation").addEventListener("click", function () {
    console.log('click on the map to add a new station');

    function addNewStation(e) {
        // Get clicked coordinate
        const clickedLocation = e.latlng;

        // Create a polyline from 'secondCityCoords' to the clicked location
        const newPolyline = L.polyline([ [secondCityCoords[1], secondCityCoords[0]], [clickedLocation.lat, clickedLocation.lng] ], {
            color: 'red',
